using System;
using System.Collections.Generic;
using System.IO;
using System.Text.Json;

namespace AssembleMonitor.Features.IoMonitor;

/// <summary>
/// I/O 비트 이름 JSON 저장/로드
/// config_iomap.json에 사용자 편집 이름 저장
/// </summary>
public static class IoMapConfig
{
    private static readonly string ConfigPath = Path.Combine(
        AppDomain.CurrentDomain.BaseDirectory, "config_iomap.json");

    private static readonly JsonSerializerOptions JsonOpts = new()
    {
        WriteIndented = true
    };

    /// <summary>
    /// 저장 형식: { "MW0100.0": "서보 ON 접점", "MW0200.5": "부저", ... }
    /// </summary>
    public static void Save(
        IEnumerable<WordViewModel> inputWords,
        IEnumerable<WordViewModel> outputWords,
