    /// </summary>
    public static void Save(
        IEnumerable<WordViewModel> inputWords,
        IEnumerable<WordViewModel> outputWords,
        IEnumerable<WordViewModel> servoSystemWords)
    {
        var dict = new Dictionary<string, string>();

        CollectNames(dict, inputWords);
        CollectNames(dict, outputWords);
        CollectNames(dict, servoSystemWords);

        var json = JsonSerializer.Serialize(dict, JsonOpts);
        File.WriteAllText(ConfigPath, json);
    }

    /// <summary>
    /// JSON에서 이름 로드 → BitViewModel.Name 덮어쓰기
    /// </summary>
    public static void Load(
        IEnumerable<WordViewModel> inputWords,
        IEnumerable<WordViewModel> outputWords,
        IEnumerable<WordViewModel> servoSystemWords)
    {
        if (!File.Exists(ConfigPath)) return;

        try
        {
            var json = File.ReadAllText(ConfigPath);
            var dict = JsonSerializer.Deserialize<Dictionary<string, string>>(json);
            if (dict == null) return;

            ApplyNames(dict, inputWords);
            ApplyNames(dict, outputWords);
            ApplyNames(dict, servoSystemWords);
        }
        catch
        {
            // JSON 파싱 실패 시 기본값 유지
        }
    }

    private static void CollectNames(Dictionary<string, string> dict, IEnumerable<WordViewModel> words)
    {
        foreach (var w in words)
            foreach (var b in w.Bits)
                dict[$"{w.MwAddress}.{b.BitIndex}"] = b.Name;
    }

    private static void ApplyNames(Dictionary<string, string> dict, IEnumerable<WordViewModel> words)
    {
        foreach (var w in words)
            foreach (var b in w.Bits)
                if (dict.TryGetValue($"{w.MwAddress}.{b.BitIndex}", out var name))
                    b.Name = name;
    }
}

