using System;
using System.IO;
using System.Text;
using System.Collections.Generic;

Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);

string filePath = @"C:\Users\Administrator\Desktop\1cellAssembleMachine\I_O 파라미터.iop";
string outPath = @"C:\Users\Administrator\Desktop\iop_result2.txt";

byte[] bytes = File.ReadAllBytes(filePath);

using var sw = new StreamWriter(outPath, false, Encoding.UTF8);
var enc949 = Encoding.GetEncoding(949);

sw.WriteLine($"File size: {bytes.Length} bytes");
sw.WriteLine();

// Full hex dump, 16 bytes per line
sw.WriteLine("=== FULL HEX DUMP ===");
for (int i = 0; i < bytes.Length; i += 16)
{
    int end = Math.Min(i + 15, bytes.Length - 1);
    var hexParts = new List<string>();
    var ascParts = new List<char>();
    for (int j = i; j <= end; j++)
    {
        hexParts.Add(bytes[j].ToString("X2"));
        ascParts.Add(bytes[j] >= 32 && bytes[j] <= 126 ? (char)bytes[j] : '.');
    }
    sw.WriteLine($"{i:X4}  {string.Join(" ", hexParts),-48}  {new string(ascParts.ToArray())}");
}

sw.WriteLine();
sw.WriteLine("=== CP949 STRING SEARCH (all non-null runs >= 4 bytes) ===");

// Find all CP949 readable strings (consecutive non-null sequences)
int runStart = -1;
for (int i = 0; i <= bytes.Length; i++)
{
    bool isNull = (i == bytes.Length || bytes[i] == 0x00);
    if (!isNull && runStart < 0) runStart = i;
    if (isNull && runStart >= 0)
    {
        int len = i - runStart;
        if (len >= 4)
        {
            byte[] chunk = new byte[len];
            Array.Copy(bytes, runStart, chunk, 0, len);
            string s = enc949.GetString(chunk);
            sw.WriteLine($"  @{runStart:X4} ({len}b): {s}");
        }
        runStart = -1;
    }
}

Console.WriteLine($"Done. Output: {outPath}");

